// frontend/src/pages/HomePage.js
import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import API from '../api/axios';
import React from 'react';

const HomePage = () => {
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    API.get('/posts')
      .then(res => setPosts(res.data))
      .finally(() => setLoading(false));
    }, []);
    if (loading) return <p>Loading posts...</p>;

  return (
    
    <main>
      <div className='home-page'>
<h2>Latest Posts</h2>
{posts.length === 0 && <p>No posts yet. Be the first to write one!</p>}
<div className='posts-grid'>
{posts.map(post => (
<div key={post._id} className='post-card'>
{post.image && (
<img src={`http://localhost:5000/uploads/${post.image}`}
alt={post.title} />
)}
<h3><Link to={`/posts/${post._id}`}>{post.title}</Link></h3>
<p>{post.body.substring(0, 120)}...</p>
<small>By {post.author?.name} Â· {new
Date(post.createdAt).toLocaleDateString()}</small>
</div>
))}
</div>
</div>
      <section style={{ textAlign: 'center' }}>
        <h2>Welcome to My Gaming Journey</h2>
        <p style={{ fontSize: '1.1rem' }}>
          I love competitive games like League of Legends, Valorant, and Brawl Stars.
        </p>
        
        {/* Make sure your PICS folder is inside the 'public' folder so this path works, 
            or import the image directly at the top of the file! */}
        <img 
          className="hero-img" 
          src="/PICS/1806be13-db84-4457-8fba-176a49df56eb.jpg" 
          alt="Gaming setup" 
        />
      </section>

      <section className="content-large">
        <h3>Why I Love Gaming</h3>
        <ul>
          <li>Improves teamwork and communication skills</li>
          <li>Builds strategic thinking and problem solving</li>
          <li>Helps me relax after a long day</li>
          <li>Connects me with friends around the world</li>
        </ul>
      </section>

      <section className="content-large">
        <h3>Featured Games</h3>
        <p>Learn more about my experience with League of Legends, Valorant, and Brawl Stars on the About page.</p>
      </section>
    </main>
  );
};

export default HomePage;
